mapper.select:
select id, fonds_code as "fondsCode", fonds_name as "fondsName", enabled, sort_order as "sortOrder", created_at as "createdAt", updated_at as "updatedAt" from am_archive_fonds where deleted_flag = false
and enabled = #{enabled}
order by sort_order, id

select id, parent_id as "parentId", category_code as "categoryCode", category_name as "categoryName", management_mode as "managementMode", volume_table_name as "volumeTableName", item_table_name as "itemTableName", table_status as "tableStatus", built_at as "builtAt", enabled, sort_order as "sortOrder", created_at as "createdAt", updated_at as "updatedAt" from am_archive_category where deleted_flag = false
and enabled = #{enabled}
order by parent_id nulls first, sort_order, id

select id, category_id as "categoryId", archive_level as "archiveLevel", field_code as "fieldCode", field_name as "fieldName", field_type as "fieldType", column_name as "columnName", text_length as "textLength", decimal_precision as "decimalPrecision", decimal_scale as "decimalScale", edit_control as "editControl", list_visible as "listVisible", list_width as "listWidth", list_sort_order as "listSortOrder", detail_visible as "detailVisible", detail_col_span as "detailColSpan", detail_sort_order as "detailSortOrder", edit_visible as "editVisible", edit_col_span as "editColSpan", edit_sort_order as "editSortOrder", exact_searchable as "exactSearchable", full_text_searchable as "fullTextSearchable", enabled, sort_order as "sortOrder", created_at as "createdAt", updated_at as "updatedAt" from am_archive_field where category_id = #{categoryId} and deleted_flag = false
and archive_level = #{archiveLevel}
and enabled = #{enabled}
order by archive_level, sort_order, id

select count(*)
from information_schema.tables
where table_schema = current_schema() and table_name = #{tableName}

select count(*)
from information_schema.columns
where table_schema = current_schema()
  and table_name = #{tableName}
  and column_name = #{columnName}

select count(*)
from pg_indexes
where schemaname = current_schema() and indexname = #{indexName}

select r.id, r.archive_level, r.parent_id, r.fonds_code, r.fonds_name, r.category_code, r.category_name, r.archive_no, r.electronic_status, r.archive_year, r.display_order, r.locked_flag, r.lock_reason, r.locked_by, r.locked_at ${selectColumns} from am_archive_record r join ${tableName} d on d.id = r.id where r.deleted_flag = false and d.deleted_flag = false and r.archive_level = #{archiveLevel}
and r.fonds_code = #{fondsCode}
and d.${condition.columnName} = #{condition.value}
and d.${condition.columnName} >= #{condition.value}
and d.${condition.columnName} <= #{condition.value}
and r.id in
#{recordId}
order by
array_position(array[
cast(#{recordId} as bigint)
], r.id)
r.sort_order, r.id desc

mapper.update:
update ${tableName}
set

    ${assignment.columnName} = #{assignment.value}

    , updated_at = localtimestamp
where id = #{id} and deleted_flag = false

update ${tableName}
set deleted_flag = true, updated_at = localtimestamp
where id = #{id} and deleted_flag = false

mapper.select:
select *
from ${tableName}
where id = #{id} and deleted_flag = false

select layout.id, layout.category_id as "categoryId", layout.surface, layout.owner_user_id as "ownerUserId", layout.field_id as "fieldId", field.field_code as "fieldCode", field.field_name as "fieldName", field.field_type as "fieldType", field.edit_control as "editControl", layout.visible, layout.list_width as "listWidth", layout.col_span as "colSpan", layout.row_order as "rowOrder", layout.col_order as "colOrder" from am_archive_field_layout layout join am_archive_field field on field.id = layout.field_id where layout.category_id = #{categoryId} and layout.surface = #{surface} and layout.deleted_flag = false and field.deleted_flag = false and field.archive_level = #{archiveLevel}
and layout.owner_user_id is null
and layout.owner_user_id = #{ownerUserId}
order by layout.row_order, layout.col_order, layout.id

mapper.update:
update am_archive_field_layout
set deleted_flag = true,
    updated_at = localtimestamp
where category_id = #{categoryId}
  and surface = #{surface}
  and deleted_flag = false
  and field_id in (
      select id
      from am_archive_field
      where category_id = #{categoryId}
        and archive_level = #{archiveLevel}
        and deleted_flag = false
  )


        and owner_user_id is null


        and owner_user_id = #{ownerUserId}
